	rowUID = payload['devEUI']
	selected = payload['selected']
	tagPath = payload["tagPathBase"]
	item = {"devEUI":rowUID, "tagPathBase":tagPath}
	if selected:
		##add to selected
		self.parent.parent.parent.getChild("table").custom.devEUIsToDelete.append(item)
	else:
		newList = []
		##else remove from selected
		for d in self.parent.parent.parent.getChild("table").custom.devEUIsToDelete:
			if d['devEUI'] == rowUID:
				continue
			else:
				newList.append(d)

		self.parent.parent.parent.getChild("table").custom.devEUIsToDelete = newList
	system.perspective.print(self.parent.parent.parent.getChild("table").custom.devEUIsToDelete)


except Exception as ex:
	system.perspective.print("Check uncheck")
	system.perspective.print(str(ex))

