if self.session.custom.tenantID != -1:
	try:
		data = device.get.listDevices(self.session.custom.tenantID)

		tagPaths = device.diagnostics.getTagPaths(data)
		values = device.diagnostics.getValues(tagPaths)

		statusData = device.diagnostics.getStatusCalculations(values)
		self.view.custom.counters = statusData
		self.view.custom.status = device.diagnostics.getStatusPaths(tagPaths, values)
		if self.view.custom.filterApplied:
			paths = self.view.custom.status[self.view.custom.filterValue]
			filteredData = []
			for r in data:
				if r['fullTagPath'] in paths:
					filteredData.append(r)

			self.view.custom.data = filteredData		
		else:

			self.view.custom.data = data

	except Exception as e:
		system.perspective.print("Error getting devices, root: " + str(e))
		self.view.custom.data = []
else:
	system.perspective.navigate(page="/")
